            // ── Layer 7: GVLK + activation channel ─────────────────────────────
            ["P7_GvlkExplain"]   = ("Checks whether the installed Windows product key is a publicly-known Generic Volume License Key (GVLK) or HWID placeholder key. GVLKs combined with permanent activation (no KMS renewal countdown) indicate TSforge, KMS38, or HWID-based piracy. Legitimate enterprise KMS-activated machines always have an active 180-day renewal cycle.",
                                    "Kiểm tra xem khóa Windows đã cài đặt có phải là Khóa Cấp phép Âm lượng Chung (GVLK) hoặc khóa HWID placeholder đã biết công khai hay không. GVLK kết hợp kích hoạt vĩnh viễn (không có đếm ngược gia hạn KMS) cho thấy TSforge, KMS38 hoặc kích hoạt HWID lậu."),
            ["P7_GvlkPermanent"] = ("LIKELY PIRACY — GVLK/placeholder key '{0}' is installed with PERMANENT activation (no KMS renewal countdown). Legitimate enterprise KMS clients always show an active 180-day countdown. This pattern matches TSforge, KMS38, or HWID activation via MAS.",
                                    "CÓ KHẢ NĂNG LẬU — Khóa GVLK/placeholder '{0}' được cài đặt với kích hoạt VĨNH VIỄN (không có đếm ngược gia hạn KMS). KMS doanh nghiệp hợp lệ luôn hiển thị đếm ngược 180 ngày. Mẫu này khớp với TSforge, KMS38 hoặc kích hoạt HWID qua MAS."),
            ["P7_GvlkWithKms"]   = ("GVLK key detected with active KMS renewal — consistent with legitimate enterprise KMS activation. Verify the KMS server above.",
